import React, { useEffect, useState } from 'react';
import { supabase } from '../services/supabaseClient';

const Listagem = () => {
  const [despesas, setDespesas] = useState([]);

  useEffect(() => {
    fetchDespesas();
  }, []);

  async function fetchDespesas() {
    const { data, error } = await supabase
      .from('compras')
      .select('*')
      .order('data_compra', { ascending: false });
    
    if (error) console.error('Erro:', error);
    else setDespesas(data);
  }

  return (
    <div>
      <h2>Minhas Despesas</h2>
      <table style={{ width: '100%', borderCollapse: 'collapse', marginTop: '20px' }}>
        <thead>
          <tr style={{ textAlign: 'left', borderBottom: '2px solid #eee', background: '#f4f4f4' }}>
            <th style={{ padding: '10px' }}>Data</th>
            <th>Descrição / Loja</th>
            <th>Detalhes</th>
            <th>Parcelas</th>
            <th>Valor Total</th>
          </tr>
        </thead>
        <tbody>
          {despesas.map((item) => (
            <tr key={item.id} style={{ borderBottom: '1px solid #eee' }}>
              <td style={{ padding: '10px' }}>{new Date(item.data_compra).toLocaleDateString('pt-BR')}</td>
              <td>
                <strong>{item.descricao}</strong><br />
                <span style={{ fontSize: '0.8em', color: '#666' }}>{item.loja}</span>
              </td>
              <td>
                <small style={{ display: 'block' }}>Ped: {item.pedido || '-'}</small>
                <small style={{ display: 'block' }}>NF: {item.nota_fiscal || '-'}</small>
              </td>
              <td>{item.parcelado ? `${item.num_parcelas}x` : 'À vista'}</td>
              <td style={{ fontWeight: 'bold' }}>
                R$ {parseFloat(item.valor_total).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

export default Listagem;
